SELECT MIN(close_price) AS min_close_price
FROM stock_prices
WHERE company_id = 101;

SELECT MAX(high_price) AS highest_price
FROM stock_prices
WHERE trading_day = '2023-10-01';

SELECT COUNT(*) AS number_of_exchanges
FROM stock_exchanges
WHERE location = 'New York';

SELECT company_name, COUNT(employees) AS number_of_employees, headquarters
FROM companies
GROUP BY company_id, company_name, headquarters;

SELECT exchange_name, location, website
FROM stock_exchanges
ORDER BY exchange_name ASC;
